"use client"

import { motion } from "framer-motion"
import { useInView } from "framer-motion"
import { useRef } from "react"

const galleryImages = [
  { id: 1, query: "malabar+biryani+luxury+food+photography", height: 600 },
  { id: 2, query: "arabian+mandi+rice+dish+premium", height: 800 },
  { id: 3, query: "grilled+alfahm+chicken+smoky+charcoal", height: 600 },
  { id: 4, query: "restaurant+interior+luxury+warm+lighting", height: 700 },
  { id: 5, query: "arabic+kabsa+food+styling+premium", height: 600 },
  { id: 6, query: "restaurant+table+setting+elegant+dining", height: 800 },
  { id: 7, query: "fried+chicken+crispy+golden+delicious", height: 600 },
  { id: 8, query: "arabic+desserts+premium+food+photography", height: 700 },
]

export default function Gallery() {
  const ref = useRef(null)
  const isInView = useInView(ref, { once: true, margin: "-100px" })

  return (
    <section ref={ref} className="bg-secondary py-24 px-4 md:py-32 lg:py-40">
      <div className="mx-auto max-w-7xl">
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={isInView ? { opacity: 1, y: 0 } : { opacity: 0, y: 20 }}
          transition={{ duration: 0.8 }}
          className="mb-16 text-center"
        >
          <div className="mx-auto mb-4 h-px w-16 bg-accent" />
          <h2 className="font-serif text-4xl font-medium text-primary md:text-5xl lg:text-6xl">Gallery</h2>
          <p className="mx-auto mt-6 max-w-2xl text-lg leading-relaxed text-foreground/70">
            A glimpse into our culinary artistry and elegant ambience
          </p>
        </motion.div>

        <div className="columns-1 gap-6 md:columns-2 lg:columns-3">
          {galleryImages.map((image, index) => (
            <motion.div
              key={image.id}
              initial={{ opacity: 0, scale: 0.95 }}
              animate={isInView ? { opacity: 1, scale: 1 } : { opacity: 0, scale: 0.95 }}
              transition={{ duration: 0.6, delay: index * 0.1 }}
              className="group relative mb-6 overflow-hidden break-inside-avoid"
            >
              <img
                src={`/generic-placeholder-icon.png?height=${image.height}&width=600&query=${image.query}`}
                alt={`Gallery image ${image.id}`}
                className="w-full transition-transform duration-700 group-hover:scale-110"
              />
              <div className="absolute inset-0 bg-primary/0 transition-all duration-500 group-hover:bg-primary/20" />
            </motion.div>
          ))}
        </div>
      </div>
    </section>
  )
}
